window.__QUIZ_DATA__=[{"id":"theory>Physics>1997>1>a","subject":"Physics","year":"1997","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"Explain the term work","images":[],"marking_scheme":"Work is the product of force and the distance moved in the direction of force.  Work is said to be done whenever a force moves a body through a distance in the direction of force hence its unit Nm = J. It is a scalar quantity.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1997>1>b","subject":"Physics","year":"1997","type":"Theory","sub_label":"b","group":"","topic":"MACHINES :","question":"Draw a diagram of a pulley system with a velocity ratio of 5.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Physics>1997>1>c>i","subject":"Physics","year":"1997","type":"Theory","sub_label":"i","group":"FINAL","topic":"MACHINES :","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:    minimum effort applied in pulling up the box    [g = 10 ms-2]","images":["data:image/png;base64,"],"marking_scheme":"m  = 70 kg; g = 10 ms-2; w = mg = 70 x 10 = 700 N  Minimum effort E = mgsin \u03b8  \u03b8 is not given but it can be calculated using SOH  \u2234sin\u03b8=2.55=12=0.5  \u03b8 = sin-1(0.5)  \u03b8 = 30o  Minimum effort = frictional force + weight of the load = 100 + 700sin 30o  = 100 + 700 x 0.5 = 100 + 350 = 450 N","marks":"3","difficulty":"3"},{"id":"theory>Physics>1997>1>c>ii","subject":"Physics","year":"1997","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MACHINES :","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   velocity ratio of the plane","images":[],"marking_scheme":"V.R=distance moved by effortdistance moved by load=52.5=2  Or   V.R=1sin \u03b8=1sin 30o=10.5=2","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>1>c>iii","subject":"Physics","year":"1997","type":"Theory","sub_label":"iii","group":"FINAL","topic":"MACHINES :","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   mechanical advantage of the plane    [g = 10 ms-2]","images":[],"marking_scheme":"M.A=LoadEffort=700450=1.56\u22431.6","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>1>c>iv","subject":"Physics","year":"1997","type":"Theory","sub_label":"iv","group":"FINAL","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   efficiency of the plane    [g = 10 ms-2]","images":[],"marking_scheme":"\u03b5=M.AV.Rx100%=1.62x100%=80%","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>1>c>v","subject":"Physics","year":"1997","type":"Theory","sub_label":"v","group":"FINAL","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   energy lost in the system    [g = 10 ms-2]","images":[],"marking_scheme":"Energy loss = (450 x 5) - (700 x 2.5) = 2250 - 1750 = 500 J","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>1>c>vi","subject":"Physics","year":"1997","type":"Theory","sub_label":"vi","group":"FINAL","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   work output of the man    [g = 10 ms-2]","images":[],"marking_scheme":"Work output of the man = F x d = mgh = 700 x 2.5 = 1750 J","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>1>c>vii","subject":"Physics","year":"1997","type":"Theory","sub_label":"vii","group":"FINAL","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"A man pulls up a box of mass 70 kg using an inclined plane of a effective length 5 m onto a platform 2.5 m high at uniform speed. If the frictional force between the box and plane is 100 N. Draw the diagram of all the forces acting on the box when in motion and calculate the:   total power developed by the man given that the time taken to raise the box onto the platform is 50 s.    [g = 10 ms-2]","images":[],"marking_scheme":"Power=F x dt=450 x 550=45W","marks":"2","difficulty":"3"},{"id":"theory>Physics>1997>2>a","subject":"Physics","year":"1997","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SIMPLE HARMONIC MOTION : FORCED VIBRATION AND RESONANCE","question":"Explain the term resonance and give two examples","images":[],"marking_scheme":"When a body is set into vibration by another body and both of them vibrate at the same natural frequency, resonance is said to occur. Example  - A diver jumping up an down at one end of a diving board.   - The soldier matching on the bridge.","marks":"1","difficulty":"1"},{"id":"theory>Physics>1997>2>b>i","subject":"Physics","year":"1997","type":"Theory","sub_label":"i","group":"","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"Describe with the aid of a labelled diagram, an experiment to show how the frequency of the note emitted by a vibrating string depends on the length of the string.","images":["data:image/png;base64,"],"marking_scheme":"Procedure:  This experiment can be done using six tuning forks of known frequency between 256 Hz and 512 Hz. With a constant weight to keep the tension constant, the wire BC is tuned in turn to each sounding fork by moving the bridge. The length will be adjusted until a throbbing note is heard when the wire is plucked and the fork is sounding at the same time, the length is recorded and the already known frequency of the fork is also recorded.  This experiment is repeated with the variation in the fork used and the lengths are determined. The graph of F against 1/L is plotted, a straight line graph is obtained passing through the origin.   Conclusion:  This shows that frequency (f) depends on the length of the spring i.e f \u03b1 1/L","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>2>b>ii","subject":"Physics","year":"1997","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"State two precautions necessary to obtain an accurate result","images":[],"marking_scheme":"- The weight suspended must be constant  - The pulley used must be smooth and free","marks":"1","difficulty":"1"},{"id":"theory>Physics>1997>2>c>i","subject":"Physics","year":"1997","type":"Theory","sub_label":"i","group":"FINAL","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"A sonometer wire is plucked and it vibrates emitting a fundamental note. State the effect on the frequency of the note if the    tension in the wire were made nine times as large with no change in the length of the wire.    [Show clearly how you arrive at your answer]","images":[],"marking_scheme":"fo=12L\u221aTMwherefo=fundamentalfrequency;L=length  T=tension;M=massperunitlengthofthespring  Sincethetensionismade9timeslargerwithnochangeinthelengthofthewire  \u21d2f1=12L\u221a9TMbut\u221a9=3  \u2234f1=12Lx3x\u221aTM  Recall  fo=12L\u221aTM  \u2234f1=3fo","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>2>c>ii","subject":"Physics","year":"1997","type":"Theory","sub_label":"ii","group":"FINAL","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"A sonometer wire is plucked and it vibrates emitting a fundamental note. State the effect on the frequency of the note if the  length of the wire were doubled with no change in the tension.    [Show clearly how you arrive at your answer]","images":[],"marking_scheme":"Lengthisdoubledwithnochangeinthetension  \u21d2f2=12 x 2L\u221aTM=14L\u221aTMandfo=12L\u221aTM  \u2234f2=12fobecause14ishalfof12","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>3>a>i","subject":"Physics","year":"1997","type":"Theory","sub_label":"i","group":"","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Sketch the form of the magnetic flux pattern due to a current flowing    in a long solenoid    [Neglect the earth's magnetic field]","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>3>a>ii","subject":"Physics","year":"1997","type":"Theory","sub_label":"ii","group":"","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Sketch the form of the magnetic flux pattern due to a current flowing  through two long straight parallel wires when the directions of the current are opposite.    [Neglect the earth's magnetic field]","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>3>b","subject":"Physics","year":"1997","type":"Theory","sub_label":"b","group":"","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Draw a labelled diagram of an electric bell and explain how it works.","images":["data:image/png;base64,"],"marking_scheme":"Electric bell works with the help of an electromagnet. When the bell is push is pressed, the electric circuit is completed (as shown above) through contact between a soft iron spring and the point of a screw N on which it rests. The iron bar T is now attracted to the electromagnet. The contact between X and N is now broken and so T is pulled back to make contact again with the screw N. So the iron T is attracted repeatedly by using a make and break device. Each time it moves towards the electromagnet, the clapper attached to T strike a gong (G). The screw is trippled with Tungsten. This is not affected by the spark which passes the gap when the contact is broken.","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>3>c>i","subject":"Physics","year":"1997","type":"Theory","sub_label":"i","group":"","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"An electric bell takes a current of 0.2 A from a battery of two dry cells connected in series. Each cell has an e.m.f of 1.5 V and an internal resistance of 1.0 \u03a9.    Calculate the effective resistance of the bell.","images":["data:image/png;base64,"],"marking_scheme":"I = 0.2 A; E1 = 1.5 V in series with E2 = 1.5 V; r1 = 1 \u03a9; r2 = 1 \u03a9  Total e.m.f = 1.5 + 1.5 = 3 V  Total internal resistance r = 1 + 1 = 2 \u03a9  E = I(R + r)  3 = 0.2(R + 2)  3 = 0.2R + 0.4  3 - 0.4 = 0.2R  2.6 = 0.2R  \u2234R=2.60.2=13\u03a9","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>3>c>ii","subject":"Physics","year":"1997","type":"Theory","sub_label":"ii","group":"","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"An electric bell takes a current of 0.2 A from a battery of two dry cells connected in series. Each cell has an e.m.f of 1.5 V and an internal resistance of 1.0 \u03a9.  What current would the bell take if the cells were arranged in parallel?","images":["data:image/png;base64,"],"marking_scheme":"Sinceitsconnectedinparallele.m.fisthesame=1.5V  Totalinternalresistance=1r=11+11=21  \u21d2r=12=0.5\u03a9  I=ER + r=1.513 + 0.5=1.513.5  \u22341=0.11A","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>4>a","subject":"Physics","year":"1997","type":"Theory","sub_label":"a","group":"","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Briefly explain what would happen to a stable element if it is bombarded by \u03b1-particles.","images":["data:image/png;base64,"],"marking_scheme":"If a stable element is bombarded by \u03b1-particles, it nucleus will not be stable and it will decay into another element with the release of energy.","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>4>b","subject":"Physics","year":"1997","type":"Theory","sub_label":"b","group":"","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Explain how the bombardment of uranium with neutrons could lead to nuclear fission chain reaction and hence nuclear explosion.","images":["data:image/png;base64,"],"marking_scheme":"The nucleus of uranium splits into two nearly equal parts when bombarded with a neutron with the release of energy","marks":"1","difficulty":"3"},{"id":"theory>Physics>1997>4>c","subject":"Physics","year":"1997","type":"Theory","sub_label":"c","group":"","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"State three characteristics of nuclear activity","images":[],"marking_scheme":"(i) A specific half life decay  (ii) They emit identifiable radiation in the process  (iii) They can be made radioactive by bombardment with nuclear particles.","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>4>d","subject":"Physics","year":"1997","type":"Theory","sub_label":"d","group":"","topic":"ENERGY : FORMS OF ENERGY","question":"State three applications of atomic energy","images":[],"marking_scheme":"(i) Many atomic energy/nuclear power station have been built to generate electricity.  (ii) In the leakage of underground pipes for the transportation of oils, it is used in detecting the area of that leakage  (iii) Nuclear weapons are also produced by atomic energy.","marks":"1","difficulty":"2"},{"id":"theory>Physics>1997>4>e","subject":"Physics","year":"1997","type":"Theory","sub_label":"e","group":"","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"State two postulates of Bohr's model of the atom and two limitations of such a model.","images":[],"marking_scheme":"Postulates:  (i) The energy of the electron could only have definite values Eo, E1 and so on, which are called the energy levels of the electron.  (ii) In those orbits where the angular momentum is a multiple of the energy is constant. The energy of the electron could only change from one level to another but not to any value between these levels.  Limitations:  (i) The model could not be applied to others and more complex atoms.  (ii) In the selection of the allowed orbits postulated, there is no theoretical basis.","marks":"1","difficulty":"2"}];